+        // Verify no overlaps: each range's end should be <= next range's start
+        for window in ranges.windows(2) {
+            let (_, end1) = window[0];
+            let (start2, _) = window[1];
+            assert!(
+                end1 <= start2,
+                "Highlight ranges should not overlap: end {} > start {}",
