+                start2
+            );
+        }
+
+        // Verify ranges are in ascending order
+        for window in ranges.windows(2) {
+            let (start1, _) = window[0];
+            let (start2, _) = window[1];
+            assert!(
+                start1 < start2,
+                "Highlight ranges should be in ascending order"
+            );
+        }
