+            Self::Cyberpunk => PackedRgba::rgb(255, 100, 200), // Hot pink
+            Self::Matrix => PackedRgba::rgb(0, 255, 65),  // Matrix green
+            Self::Retro => PackedRgba::rgb(50, 255, 100), // Terminal green
+            Self::Typewriter => PackedRgba::rgb(255, 255, 255), // White
