+/// Convert sRGB channel value to linear RGB.
+///
+/// Per WCAG 2.0 specification for relative luminance calculation.
+#[inline]
+fn srgb_to_linear(c: f64) -> f64 {
+    if c <= 0.04045 {
+        c / 12.92
+    } else {
+        ((c + 0.055) / 1.055).powf(2.4)
